mapper.select:
/* 내 문서 목록 조회 myDocuments.selectMyDocList */ SELECT M.DOC_ID , M.USER_ID , M.TMPL_ID , M.AGENT_ID , A.AGENT_NM , M.DOC_NM , M.DOC_HTML , M.SVC_TY , M.DOC_STATUS , M.NEW_YN , M.SORT_ORD , M.CREATE_DT , M.MODIFY_DT , I.ICON_CLASS_NM , C.COLOR_HEX FROM TB_MY_DOC M LEFT JOIN TB_AGT A ON M.AGENT_ID = A.AGENT_ID LEFT JOIN TB_ICON I ON A.ICON_ID = I.ICON_ID LEFT JOIN TB_COLOR C ON A.COLOR_ID = C.COLOR_ID WHERE M.USER_ID = #{userId}
AND M.SVC_TY = #{svcTy}
AND M.DOC_NM LIKE CONCAT('%', #{searchDocNm}, '%')
ORDER BY M.CREATE_DT DESC
ORDER BY M.CREATE_DT ASC
ORDER BY M.DOC_NM
ORDER BY M.SORT_ORD
ORDER BY M.CREATE_DT DESC

mapper.update:
/* 신규 문서 맨 앞 등록을 위한 정렬 순서 증가 myDocuments.incrementSortOrdByUserId */
UPDATE TB_MY_DOC
SET SORT_ORD = SORT_ORD + 1
  , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}

mapper.insert:
/* 나의 문서 보고서 저장 myDocuments.saveReport */
INSERT INTO TB_MY_DOC (
      DOC_ID
    , USER_ID
    , TMPL_ID
    , AGENT_ID
    , DOC_NM
    , DOC_HTML
    , ORIGIN_HTML
    , SVC_TY
    , R_CONTENT
    , SORT_ORD
    , NEW_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
      #{docId}
    , #{userId}
    , #{tmplId, jdbcType=VARCHAR}
    , #{agentId, jdbcType=VARCHAR}
    , #{docNm, jdbcType=VARCHAR}
    , #{docHtml, jdbcType=VARCHAR}
    , #{originHtml, jdbcType=VARCHAR}
    , #{svcTy, jdbcType=VARCHAR}
    , #{rContent, jdbcType=VARCHAR}
    , #{sortOrd, jdbcType=INTEGER}
    , #{newYn, jdbcType=CHAR}
    , NOW()
    , NOW()
)
ON DUPLICATE KEY UPDATE
      TMPL_ID      = VALUES(TMPL_ID)
    , AGENT_ID     = VALUES(AGENT_ID)
    , DOC_NM       = VALUES(DOC_NM)
    , DOC_HTML     = VALUES(DOC_HTML)
    , ORIGIN_HTML  = VALUES(ORIGIN_HTML)
    , SVC_TY       = VALUES(SVC_TY)
    , R_CONTENT    = VALUES(R_CONTENT)
    , SORT_ORD     = COALESCE(#{sortOrd, jdbcType=INTEGER}, SORT_ORD)
    , MODIFY_DT    = NOW()

mapper.update:
/* 내 문서 신규 여부 변경 myDocuments.updateNewYn */
UPDATE TB_MY_DOC
SET NEW_YN = #{newYn}
  , MODIFY_DT = NOW()
WHERE DOC_ID = #{docId}
    AND USER_ID = #{userId}

/* 내 문서명 변경 myDocuments.updateDocNm */
UPDATE TB_MY_DOC
SET DOC_NM = #{docNm}
  , MODIFY_DT = NOW()
WHERE DOC_ID = #{docId}
    AND USER_ID = #{userId}

/* 내 문서 정렬순서 일괄 수정 myDocuments.updateSortOrd */
UPDATE TB_MY_DOC
SET SORT_ORD = CASE DOC_ID

    WHEN #{item.docId} THEN #{item.sortOrd}

END
  , MODIFY_DT = NOW()
WHERE USER_ID = #{userId}
    AND DOC_ID IN

    #{item.docId}

mapper.delete:
/* 내 문서 삭제 myDocuments.deleteMyDoc */
DELETE FROM TB_MY_DOC
WHERE DOC_ID = #{docId}
    AND USER_ID = #{userId}

mapper.update:
/* 삭제된 문서 공유 비활성화 myDocuments.disableDocShareByDocId */
UPDATE TB_MY_DOC_SHARE
SET USE_YN = 'N'
  , MODIFY_DT = NOW()
WHERE DOC_ID = #{docId}
    AND USE_YN = 'Y'

mapper.select:
/* 공유 문서 원본 DOC_ID 조회 myDocuments.selectDocIdByShareId */
SELECT DOC_ID
FROM TB_MY_DOC_SHARE
WHERE SHARE_ID = #{shareId}
    AND TO_USER_ID = #{userId}
    AND SAVE_YN = 'N'
    AND USE_YN = 'Y'

/* 공유 문서 프리뷰용 원본 DOC_ID 조회 myDocuments.selectDocIdByShareIdForInfo */
SELECT DOC_ID
FROM TB_MY_DOC_SHARE
WHERE SHARE_ID = #{shareId}

mapper.update:
/* 공유 문서 저장 정보 업데이트 myDocuments.updateDocShareSave */
UPDATE TB_MY_DOC_SHARE
SET SAVE_YN = 'Y'
    , SAVE_DOC_ID = #{saveDocId}
    , MODIFY_DT = NOW()
WHERE SHARE_ID = #{shareId}

mapper.insert:
/* 내 문서 공유 정보 등록 myDocuments.insertDocShare */
INSERT INTO TB_MY_DOC_SHARE (
    SHARE_ID
    , DOC_ID
    , FROM_USER_ID
    , TO_USER_ID
    , SHARE_MSG
    , SAVE_YN
    , SAVE_DOC_ID
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
) VALUES (
    #{shareId}
    , #{docId}
    , #{fromUserId}
    , #{toUserId}
    , #{shareMsg, jdbcType=VARCHAR}
    , 'N'
    , NULL
    , 'Y'
    , NOW()
    , NULL
)
